@interface WBVIPFeatureManager()

@property(strong, nonatomic) NSArray<WBVIPFeatureModel*> *features;

@end

@implementation WBVIPFeatureManager


+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBVIPFeatureManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        NSData *data = [NSData dataWithContentsOfFile:[[NSBundle mainBundle] pathForResource:@"PopView" ofType:@"json"]];
        NSError *err = nil;
        id json = [NSJSONSerialization JSONObjectWithData:data options:NSJSONReadingMutableContainers error:&err];
        NSAssert([json isKindOfClass:NSArray.class], @"error reading PopView.json");
        self.features = [[NSArray modelArrayWithClass:WBVIPFeatureModel.class json:json] mutableCopy];
    }
    return self;
}

- (void)overridesWithList: (NSArray<NSString*> *)featureList andFeatureConfigs: (NSArray<WBVIPFeatureModel*> *)configs {
    NSMutableArray *newFeatures = [NSMutableArray array];

    for (NSString *featureName in featureList) {
        for(WBVIPFeatureModel *feature in self.features) {
            if ([featureName isEqualToString:feature.code_name]) {
                for(WBVIPFeatureModel *remoteConfig in configs) {
                    if ([remoteConfig.code_name isEqualToString:feature.code_name]) {
                        [feature overridesWith:remoteConfig];
                        break;
                    }
                }
                [newFeatures addObject:feature];
            }
        }
    }
    self.features = newFeatures;
}

- (NSArray<WBVIPFeatureModel*> *)getFeatures {
    return self.features;
}

@end

