@implementation WBSettingManager

NSString * const kWBAdsAppId = @"WBAdsAppId";

#pragma mark singleton & init

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBSettingManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    self.userDefaults = [NSUserDefaults standardUserDefaults];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleShareLinkNotification:) name:WBPresentShareUrlNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleShareTitleNotification:) name:WBPresentShareContentNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(backToOriginalShareInfoNotification) name:WBBackToOriginalShareUrlNotification object:nil];
    return self;
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)handleShareLinkNotification:(NSNotification *)notification {
    // 从通知中获取 userInfo 字典
    NSDictionary *shareLinkInfo = [notification userInfo];
    NSString *shareLink = [shareLinkInfo objectForKey:@"shareUrl"];
    if(shareLink) {
        self.ShareURL = shareLink;
    } else {
        // 使用user/token里面的默认分享链接
    }
}

- (void)handleShareTitleNotification:(NSNotification *)notification {
    // 从通知中获取 userInfo 字典
    NSDictionary *shareContentInfo = [notification userInfo];
    NSString *shareTitle = [shareContentInfo objectForKey:@"shareTitle"];
    NSString *shareDescription = [shareContentInfo objectForKey:@"shareDescription"];
    if(shareTitle) {
        self.ShareTitle = shareTitle;
    } else {
        // 使用user/token里面的默认分享标题
    }
    if(shareDescription) {
        self.ShareDescription = shareDescription;
    } else {
        self.ShareDescription = @"";
    }
}

// 分享完当前打开的网页之后，重置为默认分享网页（分享落地页）
- (void)backToOriginalShareInfoNotification {
    self.ShareURL = self.originalShareUrl;
    self.ShareTitle = self.OriginalShareTitle;
    self.ShareDescription = self.OriginalShareDescription;
}

- (BOOL)EnableADS {
    return [self isAdsAppIdValid:self.ADSAppId];
}

- (BOOL)isAdsAppIdValid:(NSString *)adsAppId {
    return adsAppId.length && [adsAppId integerValue] != 0;
}

// 判断是否终身会员
- (BOOL)isLifetimeMemberWithExpireDate:(NSString *)expireDateString {
    if (!self.IsSVIP) {
        return NO;
    }
    // 创建临界日期
    static NSDate *criticalDate;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSDateComponents *comps = [[NSDateComponents alloc] init];
        comps.year = 2098;
        comps.month = 12;
        comps.day = 31;
        criticalDate = [[NSCalendar currentCalendar] dateFromComponents:comps];
    });

    // 转换传入的日期字符串
    static NSDateFormatter *formatter;
    static dispatch_once_t formatterToken;
    dispatch_once(&formatterToken, ^{
        formatter = [[NSDateFormatter alloc] init];
        formatter.dateFormat = @"yyyy-MM-dd";
    });
    NSDate *expireDate = [formatter dateFromString:expireDateString];

    if (!expireDate) {
        return NO;
    }
    return [expireDate compare:criticalDate] == NSOrderedDescending;
}

- (void)syncWithUserInfo:(WBUserInfoHttpModel *)userInfo {
    self.IsVIP = userInfo.is_vip;
    self.IsSVIP = userInfo.is_svip;
    self.IsTrial = userInfo.is_trial;
    self.IsNew = userInfo.is_new;
    self.HasPassword = userInfo.has_password;
    self.Mobile = userInfo.mobile;
    self.VIPExpires = [WBUtility convertUTC2Local:userInfo.vip_expires];
    self.SVIPExpires = [WBUtility convertUTC2Local:userInfo.svip_expires];
    self.VIPExpires = [self.VIPExpires substringToIndex:10];
    self.SVIPExpires = [self.SVIPExpires substringToIndex:10];
    self.ShowExpirationAlert = userInfo.expirationAlert;
    self.Benefit = userInfo.benefit;
    self.IsLifetimeMember = [self isLifetimeMemberWithExpireDate:self.SVIPExpires];
    if (self.IsVIP) {
        [WBEventManager logAppAdVipClose:@"0"];
    } else {
        [WBEventManager logAppAdVipClose:@"Not vip, ads run."];
    }
}

- (void)syncWithAppVersionInfo:(WBAppVersionInfoHttpModel *)appVersionInfo {
    self.HasUpdate = appVersionInfo.has_update;
    self.RemindUpdate = appVersionInfo.remind_update;
    self.ForceUpdate = appVersionInfo.force_update;
    self.TrackId = appVersionInfo.track_id;
    self.UpdateDescription = appVersionInfo.desc;
}

- (void)syncWithHeatBeatResponse:(WBHeartBeatHttpModel *)heartBeat {
    self.HasNewNotice = heartBeat.new_sys_msg;
    self.HasNewMessage = heartBeat.new_css_msg;
    self.HasNewShare = heartBeat.new_share_msg;
    if (self.IsTrial && heartBeat.trial_over) {
        self.IsTrial = FALSE;
    }
    if (self.IsVIP && heartBeat.vip_expired) {
        self.IsVIP = FALSE;
    }
#ifdef VIP
    self.IsVIP = true;
    self.IsTrial = false;
#endif
    if (heartBeat.log_rate) {
        self.LogRate = heartBeat.log_rate;
    }
    if (heartBeat.hb_rate) {
        self.HeartBeatRate = heartBeat.hb_rate;
    }
    PostNotificationOnMainThread(WBUserMsgStatusUpdateNotification, nil);
}

- (void)syncWithCompatibles:(WBCompatibleHttpModel *)compatibles {
    self.DyldSect = compatibles.dysect;
    self.DyldOffset = compatibles.dyos;
}

- (void)syncWithStrings:(WBStringsHttpModel *)strings {
    self.TrialOverMsg = strings.trial_over_msg;
    self.TrialRemindMsg = strings.trial_remind_msg;
}

- (void)syncWithUrls:(WBUrlsHttpModel *)urls {
    self.PrivacyURL = urls.privacy;
    self.UserTermURL = urls.agreement;
    self.ShareURL = urls.share;
    self.originalShareUrl = urls.share;
}

- (void)syncWithAds:(WBAdsHttpModel *)ads {
    self.splashAdEnableShow = ads.adsSplashEnableShow;
    self.bannerAdEnableShow = ads.adsBannerEnableShow;
    self.nativeAdEnableShow = ads.adsNativeEnableShow;
    self.rewardAdEnableShow = ads.adsRewardFloatingEnableShow;
    self.myVCRewardAdRowEnableShow = ads.adsRewardMyVCEnableShow;

    // 展示位置
    self.bannerAdPosition = ads.bannerAdPosition;
    self.nativeAdPosition = ads.nativeAdPosition;
}

- (void)syncWithConfigs:(WBConfigsHttpModel *)configs {
    self.ADSAppId = configs.adsAppId; // 应用ID
    self.splashSlotId = configs.adsSplashSlotId;  // 开屏广告位
    self.bannerSlotId = configs.adsBannerSlotId;  // Banner广告位
    self.rewardSlotId = configs.adsRewardSlotId;    // 激励广告位
    self.interstitialSlotId = configs.adsInterstitialSlotId; // 插屏广告位
    self.nativeSlotId = configs.adsNativeSlotId;  // 信息流广告位

    // 展示开关
    self.splashAdEnableShow = configs.adsSplashEnableShow;    // 开屏广告是否显示
    self.bannerAdEnableShow = configs.adsBannerEnableShow;    // banner广告是否显示
